#include <stdio.h>

int binary_search(int arr[], int n, int t) {
    int lo = 0, hi = n - 1;
    while (lo <= hi) {
        int mid = (lo + hi) / 2;
        if (arr[mid] == t) return 1;
        else if (arr[mid] < t) lo = mid + 1;
        else hi = mid - 1;
    }
    return 0;
}

int main() {
    int n, t; scanf("%d %d", &n, &t);
    int arr[1001];
    for (int i = 0; i < n; i++) scanf("%d", &arr[i]);
    printf("%s\n", binary_search(arr, n, t) ? "YES" : "NO");
    return 0;
}
